 {"id":"bd-32ph","title":"Task: Add CLI flags for model and reranker selection","description":"## Task: Add CLI Flags for Model and Reranker Selection

Extend xf CLI to support **winner selection** from the bake-off, with proper config precedence, validation, and shell completions.

## Config Precedence (highest to lowest)
1. CLI flags (`--model=`, `--reranker=`)
2. Environment variables (`XF_MODEL`, `XF_RERANKER`, `XF_DIMS`)
3. Config file (`~/.config/xf/config.toml`)
4. Compiled-in defaults (bake-off winner)

## New CLI Flags
```
# Search flags
xf search "query" --semantic              # Enable semantic search
xf search "query" --model=<name>          # Override embedding model
xf search "query" --dimensions=<N>        # MRL dimension override (256/512/768/1024)
xf search "query" --rerank                # Enable reranking
xf search "query" --reranker=<name>       # Override reranker model
xf search "query" --daemon / --no-daemon  # Force daemon mode on/off
xf search "query" --top-k=<N>            # Number of results (default 20)
xf search "query" --rerank-top=<N>       # Candidates to rerank (default 100)

# Daemon management
xf daemon start [--model=<name>] [--foreground]
xf daemon stop
xf daemon status [--json]

# Model info
xf models list [--json]                   # Show available models
xf models info <name>                     # Show model details
```

## Config File Format (`~/.config/xf/config.toml`)
```toml
[semantic]
model = "static-retrieval-mrl-en-v1"    # Default embedder
dimensions = 768                         # Default MRL dims
reranker = "flashrank-nano"             # Default reranker
rerank = false                           # Reranking off by default
daemon = true                            # Use daemon by default

[daemon]
idle_timeout_secs = 300
nice_level = 10
memory_limit_mb = 1024
socket_path = "/tmp/xf-daemon.sock"     # Override socket location
```

## Implementation Structure
```rust
// src/cli/semantic_opts.rs
use clap::Args;

#[derive(Args, Debug, Clone)]
pub struct SemanticOpts {
    /// Enable semantic search
    #[arg(long)]
    pub semantic: bool,

    /// Embedding model to use
    #[arg(long, value_name = "MODEL")]
    pub model: Option<String>,

    /// MRL dimension override (256, 512, 768, 1024)
    #[arg(long, value_name = "DIMS", value_parser = validate_mrl_dims)]
    pub dimensions: Option<usize>,

    /// Enable reranking of results
    #[arg(long)]
    pub rerank: bool,

    /// Reranker model to use
    #[arg(long, value_name = "RERANKER")]
    pub reranker: Option<String>,

    /// Use warm model daemon
    #[arg(long, conflicts_with = "no_daemon")]
    pub daemon: bool,

    /// Force direct inference (no daemon)
    #[arg(long, conflicts_with = "daemon")]
    pub no_daemon: bool,

    /// Number of results to return
    #[arg(long, default_value = "20")]
    pub top_k: usize,

    /// Number of candidates to rerank
    #[arg(long, default_value = "100")]
    pub rerank_top: usize,
}

fn validate_mrl_dims(s: &str) -> Result<usize, String> {
    let dims: usize = s.parse().map_err(|_| format!("Invalid dimension: {}", s))?;
    match dims {
        256 | 512 | 768 | 1024 => Ok(dims),
        _ => Err(format!("MRL dimensions must be 256, 512, 768, or 1024; got {}", dims)),
    }
}

// src/config/resolve.rs
pub struct ResolvedConfig {
    pub model: String,
    pub dimensions: usize,
    pub reranker: Option<String>,
    pub use_rerank: bool,
    pub use_daemon: bool,
    pub top_k: usize,
    pub rerank_top: usize,
}

impl ResolvedConfig {
    pub fn resolve(cli: &SemanticOpts) -> Result<Self> {
        let file_config = load_config_file()?;
        let env_config = load_env_config()?;

        Ok(Self {
            model: cli.model.clone()
                .or(env_config.model)
                .or(file_config.model)
                .unwrap_or_else(|| DEFAULT_EMBEDDER.to_string()),
            dimensions: cli.dimensions
                .or(env_config.dimensions)
                .or(file_config.dimensions)
                .unwrap_or(768),
            reranker: cli.reranker.clone()
                .or(env_config.reranker)
                .or(file_config.reranker),
            use_rerank: cli.rerank || file_config.rerank.unwrap_or(false),
            use_daemon: if cli.no_daemon { false }
                else if cli.daemon { true }
                else { file_config.daemon.unwrap_or(true) },
            top_k: cli.top_k,
            rerank_top: cli.rerank_top,
        })
    }
}
```

## Model Name Validation
```rust
pub fn validate_model_name(name: &str, registry: &ModelRegistry) -> Result<()> {
    if !registry.has_embedder(name) {
        let available: Vec<_> = registry.embedder_names().collect();
        let suggestion = find_closest_match(name, &available);
        let mut msg = format!("Unknown model: {:?}. Available models:\n", name);
        for m in &available {
            msg.push_str(&format!("  - {}\n", m));
        }
        if let Some(s) = suggestion {
            msg.push_str(&format!("\nDid you mean {:?}?", s));
        }
        return Err(anyhow::anyhow!(msg));
    }
    Ok(())
}
```

