use clap_complete::{generate_to, shells::*};

pub fn generate_completions(cmd: &mut clap::Command) -> Result<()> {
    let outdir = dirs::data_dir()
        .unwrap_or_else(|| PathBuf::from("."))
        .join("xf/completions");
    std::fs::create_dir_all(&outdir)?;

    generate_to(Bash, cmd, "xf", &outdir)?;
    generate_to(Zsh, cmd, "xf", &outdir)?;
    generate_to(Fish, cmd, "xf", &outdir)?;
    Ok(())
}
