fn test_config_precedence_cli_wins() {
    let cli = SemanticOpts { model: Some("bge-small".into()), ..Default::default() };
    std::env::set_var("XF_MODEL", "minilm");
    let resolved = ResolvedConfig::resolve(&cli).unwrap();
    assert_eq!(resolved.model, "bge-small", "CLI should override env");
}

