mod plain_impl {
    //! Fallback implementation when rich feature is disabled
    //! Provides the same API but with plain text output

    pub struct Console;

    impl Console {
        pub fn new() -> Self { Self }
        pub fn print(&self, text: &str) { println!("{}", text); }
        pub fn rule(&self, title: Option<&str>) {
            if let Some(t) = title {
                println!("--- {} ---", t);
