        title: Option<String>,
    }

    impl Panel {
        pub fn from_text(text: &str) -> Self {
            Self { content: text.to_string(), title: None }
        }
        pub fn title(mut self, title: &str) -> Self {
            self.title = Some(title.to_string());
            self
        }
        pub fn border_style(self, _: impl Into<Color>) -> Self { self }
    }

    pub struct Table {
        title: Option<String>,
