// In src/error.rs
use crate::output::{Output, messages::MessagePanel};

/// Convert XfError to MessagePanel for display
impl From<&XfError> for MessagePanel {
    fn from(err: &XfError) -> Self {
        match err {
            XfError::ArchiveNotFound(path) => MessagePanel::archive_not_found(path),
            XfError::ArchiveNotReadable(path) => MessagePanel::error("Archive Not Readable", &format!("Cannot read archive at: {}", path.display()))
                .with_code(ErrorCode::ArchiveNotReadable)
                .with_suggestion("Check file permissions"),
            XfError::IndexNotFound => MessagePanel::error("Index Not Found", "Search index does not exist")
                .with_code(ErrorCode::IndexMissing)
                .with_suggestion("Run 'xf index' to build the search index"),
            XfError::IndexStale => MessagePanel::index_outdated(),
            XfError::IndexCorrupt(msg) => MessagePanel::error("Index Corrupted", msg)
                .with_code(ErrorCode::IndexCorrupt)
                .with_suggestion("Run 'xf index --rebuild' to recreate the index"),
            XfError::NoResults(query) => MessagePanel::no_results(query),
            XfError::InvalidQuery(msg) => MessagePanel::error("Invalid Query", msg)
                .with_code(ErrorCode::InvalidQuery)
                .with_suggestion("Check query syntax with 'xf help search'"),
            XfError::DatabaseError(msg) => MessagePanel::error("Database Error", msg)
                .with_code(ErrorCode::DatabaseError)
                .with_suggestion("Try running 'xf doctor' to diagnose"),
            XfError::ConfigError(msg) => MessagePanel::error("Configuration Error", msg)
                .with_code(ErrorCode::ConfigInvalid)
                .with_suggestion("Check your configuration file"),
            XfError::IoError(err) => MessagePanel::error("I/O Error", &err.to_string())
                .with_code(ErrorCode::IoError),
            XfError::Other(msg) => MessagePanel::error("Error", msg),
        }
    }
}

/// Handle errors with styled output
pub fn handle_error(err: XfError, output: &Output) {
    let panel: MessagePanel = (&err).into();

    // Add details in verbose mode
    if output.is_verbose() {
        if let Some(source) = err.source() {
            panel.clone().with_detail(&format!("Caused by: {}", source)).render(output);
            return;
        }
    }

    panel.render(output);

    // In debug mode, print backtrace
    if output.is_debug() {
        if let Some(bt) = err.backtrace() {
            output.print_debug(&format!("Backtrace:\n{}", bt));
        }
    }
}
