// tests/daemon_config_e2e.rs
use std::io::Write;
use tempfile::NamedTempFile;

#[test]
fn test_config_load_valid_toml() {
    let config_content = r#"
[daemon]
nice_level = 15
memory_limit_mb = 1024
max_threads = 2
idle_timeout_secs = 600
io_priority = "best_effort"
socket_path = "/tmp/test-xf.sock"
"#;

    let mut file = NamedTempFile::new().unwrap();
    file.write_all(config_content.as_bytes()).unwrap();
    let path = file.path().to_path_buf();

    let config = DaemonConfig::load(Some(&path)).unwrap();

    assert_eq!(config.resources.nice_level, 15);
    assert_eq!(config.resources.memory_limit_mb, 1024);
    assert_eq!(config.resources.max_threads, 2);
    assert_eq!(config.idle_timeout, Duration::from_secs(600));

    tracing::info!(?config, "Config loaded from TOML");
}

#[test]
fn test_config_load_invalid_toml() {
    let config_content = "this is not valid toml {{{";

    let mut file = NamedTempFile::new().unwrap();
    file.write_all(config_content.as_bytes()).unwrap();
    let path = file.path().to_path_buf();

    let result = DaemonConfig::load(Some(&path));
    assert!(result.is_err());
    tracing::info!(error = %result.unwrap_err(), "Invalid TOML correctly rejected");
}

#[test]
fn test_config_load_missing_file_uses_defaults() {
    let path = PathBuf::from("/nonexistent/path/config.toml");
    let config = DaemonConfig::load(Some(&path)).unwrap();

    // Should use defaults
    assert_eq!(config.resources.nice_level, 10);
    assert_eq!(config.resources.memory_limit_mb, 2048);
    tracing::info!("Missing file correctly uses defaults");
}

