    let daemon1 = DaemonProcess::spawn().await.unwrap();
    let result = DaemonProcess::spawn_same_socket().await;
    assert!(result.is_err());
    // First daemon should still be running
    assert!(daemon1.socket_path.exists());
}

#[tokio::test]
async fn test_stale_lock_file_detected() {
    // Create stale PID file pointing to non-existent process
    let pid_path = temp_pid_path();
    std::fs::write(&pid_path, "99999999").unwrap();

    // Daemon should detect stale lock and start anyway
    let daemon = DaemonProcess::spawn_with_pid_path(&pid_path).await;
    assert!(daemon.is_ok());
}
